import{_ as i,o as d,c as r,a2 as e}from"./chunks/framework.N6Nd-M9-.js";const g=JSON.parse('{"title":"从产品生意到同创生意","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/组长培训/从产品生意到同创生意.md","filePath":"notes/培训/组长培训/从产品生意到同创生意.md"}'),o={name:"notes/培训/组长培训/从产品生意到同创生意.md"};function s(a,t,n,l,b,p){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="从产品生意到同创生意" tabindex="-1">从产品生意到同创生意 <a class="header-anchor" href="#从产品生意到同创生意" aria-label="Permalink to &quot;从产品生意到同创生意&quot;">​</a></h1><blockquote><p>理解两种生意的本质区别，构建可复制、可传承的事业系统</p></blockquote><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;margin:20px 0;"><div class="tc-blue tc-bold tc-center" style="font-size:20px;margin-bottom:20px;">📑 内容导航</div><div style="display:flex;flex-wrap:wrap;gap:12px;justify-content:center;"><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">🎯</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">核心理念</div><div class="tc-muted tc-sm">两种生意<br>本质区别</div></div><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">💎</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">核心观点</div><div class="tc-muted tc-sm">金字塔理论<br>心智成熟</div></div><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">🚀</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">团队要求</div><div class="tc-muted tc-sm">野心公心<br>严谨担当</div></div></div></div><hr><h2 id="🎯-一、核心理念-两种生意的本质区别" tabindex="-1">🎯 一、核心理念：两种生意的本质区别 <a class="header-anchor" href="#🎯-一、核心理念-两种生意的本质区别" aria-label="Permalink to &quot;🎯 一、核心理念：两种生意的本质区别&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:16px 0;"><div style="flex:1;min-width:250px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:20px;"><div class="tc-orange tc-bold" style="font-size:18px;margin-bottom:10px;">📦 产品生意</div><div class="tc-body" style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;"> 本质是<strong>卖货</strong>。 </div></div><div style="flex:1;min-width:250px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;"><div class="tc-green tc-bold" style="font-size:18px;margin-bottom:10px;">🏢 同创生意</div><div class="tc-body" style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;"> 本质是利用产品作为<strong>&quot;工具&quot;</strong>，去学习和构建一个<strong class="tc-green">可复制、可传承、可壮大</strong>的事业系统。 </div></div></div><hr><h2 id="🎯-二、核心观点阐述" tabindex="-1">🎯 二、核心观点阐述 <a class="header-anchor" href="#🎯-二、核心观点阐述" aria-label="Permalink to &quot;🎯 二、核心观点阐述&quot;">​</a></h2><h3 id="_2-1-成功如同金字塔-补齐根基-方能登顶" tabindex="-1">2.1 成功如同金字塔：补齐根基，方能登顶 <a class="header-anchor" href="#_2-1-成功如同金字塔-补齐根基-方能登顶" aria-label="Permalink to &quot;2.1 成功如同金字塔：补齐根基，方能登顶&quot;">​</a></h3><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-body" style="font-size:14px;line-height:1.8;"> 可见的<strong>&quot;塔尖&quot;</strong>（职位、业绩）由下面看不见的<strong>&quot;根基&quot;</strong>决定。 </div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">🏗️ 根基是什么</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 是日常的销售工作、拜访经验、成交流程（如5864、销售五步）以及对企业文化（愿景、使命、价值观）的深刻理解。 </div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-orange tc-bold" style="font-size:16px;margin-bottom:12px;">⚠️ 关键认知</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 对企业文化的认同程度，决定了你职位的高度。 </div></div><h3 id="_2-2-从体力赚钱到经验赚钱-个人成长的跃迁" tabindex="-1">2.2 从体力赚钱到经验赚钱：个人成长的跃迁 <a class="header-anchor" href="#_2-2-从体力赚钱到经验赚钱-个人成长的跃迁" aria-label="Permalink to &quot;2.2 从体力赚钱到经验赚钱：个人成长的跃迁&quot;">​</a></h3><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-body" style="font-size:14px;line-height:1.8;"> 高层（如<strong>&quot;军长&quot;</strong>）不需要自己<strong>&quot;打枪&quot;</strong>，而是依靠统领全局的<strong>&quot;经验&quot;</strong>。 <br><br> 同样的地区、产品、话术，业绩不同的核心在于是否用心、是否懂得<strong>&quot;讲故事&quot;</strong>让产品<strong>&quot;活&quot;</strong>起来。 </div></div><h3 id="_2-3-心智成熟是内心强大的表现" tabindex="-1">2.3 心智成熟是内心强大的表现 <a class="header-anchor" href="#_2-3-心智成熟是内心强大的表现" aria-label="Permalink to &quot;2.3 心智成熟是内心强大的表现&quot;">​</a></h3><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-green tc-bold" style="font-size:16px;margin-bottom:12px;">🌟 成熟的标志</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 能够接受之前不能接受的事情。 </div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">🤝 团队共处</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 在团队中要学会妥协，与不喜欢的人和事共处，允许差异的存在。这不是软弱，而是<strong>包容的格局</strong>。 </div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-red tc-bold" style="font-size:16px;margin-bottom:12px;">💪 内心强大是练出来的</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 通过主动去做不敢做的事（如陌生拜访、挑战权威）来磨练。<strong>逃避问题是懦弱，直面问题才能成长。</strong></div></div><h3 id="_2-4-事业的-附加值-比收入本身更重要" tabindex="-1">2.4 事业的&quot;附加值&quot;比收入本身更重要 <a class="header-anchor" href="#_2-4-事业的-附加值-比收入本身更重要" aria-label="Permalink to &quot;2.4 事业的&quot;附加值&quot;比收入本身更重要&quot;">​</a></h3><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-body" style="font-size:14px;line-height:1.8;"> 如同城市房产比农村自建房价值高，是因为附加了教育、医疗、人脉等资源。 </div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">💎 同创生意的&quot;附加值&quot;</div><div class="tc-body" style="font-size:14px;line-height:1.8;"><strong>1. 敬畏之心</strong>：对事业、规则保持敬畏，而非散漫随意。 <br><br><strong>2. 生命影响生命</strong>：成就他人，用心教授，组建和壮大团队。 <br><br><strong>3. 营造积极氛围</strong>：以身作则，传递正能量，带动他人。 </div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-green tc-bold" style="font-size:16px;margin-bottom:12px;">🎯 结果</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 拥有这些附加值，个人价值才会升高，才能获得真正的尊重和长远发展。 </div></div><hr><h2 id="📌-三、对团队成员的要求" tabindex="-1">📌 三、对团队成员的要求 <a class="header-anchor" href="#📌-三、对团队成员的要求" aria-label="Permalink to &quot;📌 三、对团队成员的要求&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:16px 0;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">🔥</div><div class="tc-blue tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">要有野心，敢于展现</div><div class="tc-body tc-sm" style="line-height:1.6;"> 不要隐藏事业心，用行动和结果去争取。 </div></div><div style="flex:1;min-width:200px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">❤️</div><div class="tc-green tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">要有公心，用心教人</div><div class="tc-body tc-sm" style="line-height:1.6;"> 怕麻烦就带不好团队。组建团队是为了共同成就，团队的壮大是你成功的前提。 </div></div><div style="flex:1;min-width:200px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">📐</div><div class="tc-orange tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">要严谨务实，戒除算计</div><div class="tc-body tc-sm" style="line-height:1.6;"> 扎实做好每一个销售动作，不要在小事上斤斤计较（如一瓶水、一句话），心思要放在事业上。 </div></div><div style="flex:1;min-width:200px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">⚡</div><div class="tc-red tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">要有担当，不谋财害命</div><div class="tc-body tc-sm" style="line-height:1.6;"> 如果没有强烈的事业心和持续的努力，就不要带人，否则是在浪费他人的时间和生命。 </div></div></div><hr><div class="tc-center" style="background:rgba(102,126,234,0.08);border:2px solid rgba(102,126,234,0.2);border-radius:12px;padding:24px;margin:20px 0;"><div class="tc-blue tc-bold" style="font-size:18px;margin-bottom:12px;">📝 总结</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 这是一门需要<strong>用产品为工具，构建可传承系统</strong>的<strong>&quot;同创生意&quot;</strong>。它要求我们以创业者心态，扎实根基、锻造强大内心、并创造超越业绩的附加值。唯有如此，才能获得维持奋斗一生的事业，而不仅仅是一份工作。 </div></div>',27)])])}const x=i(o,[["render",s]]);export{g as __pageData,x as default};
